/* ---- Tokenizer ---- */

/* Token types */
#define TOK_WORD   0
#define TOK_QUOTED 1
#define TOK_BLOCK  2

char token_buf[MAX_TOKENS][MAX_TOKEN_LEN];
int  token_type[MAX_TOKENS];
int  token_count;

/* tokenize_line: split a line into tokens.
 * Returns token count, or -1 on syntax error.
 * Fills token_buf[], token_type[], token_count.
 */
int tokenize_line(char *line) {
    int i = 0;
    token_count = 0;

    while (line[i]) {
        /* skip whitespace */
        while (line[i] == 32 || line[i] == 9) /* space, tab */
            i = i + 1;

        if (line[i] == 0) break;

        /* comment — rest of line ignored */
        if (line[i] == 35) /* '#' */
            break;

        if (token_count >= MAX_TOKENS) break;

        if (line[i] == 34) { /* '"' — quoted string */
            i = i + 1; /* skip opening quote */
            int t = 0;
            while (line[i] && line[i] != 34) {
                if (line[i] == 92 && line[i + 1]) { /* backslash escape */
                    i = i + 1;
                    if (line[i] == 110) /* \n */
                        token_buf[token_count][t] = 10;
                    else if (line[i] == 116) /* \t */
                        token_buf[token_count][t] = 9;
                    else
                        token_buf[token_count][t] = line[i];
                    t = t + 1;
                    i = i + 1;
                } else {
                    if (t < MAX_TOKEN_LEN - 1) {
                        token_buf[token_count][t] = line[i];
                        t = t + 1;
                    }
                    i = i + 1;
                }
            }
            if (line[i] != 34) { /* unterminated quote */
                uart_puts("error: unterminated quote");
                uart_newline();
                return -1;
            }
            i = i + 1; /* skip closing quote */
            token_buf[token_count][t] = 0;
            token_type[token_count] = TOK_QUOTED;
            token_count = token_count + 1;

        } else if (line[i] == 123) { /* '{' — brace block */
            int depth = 1;
            int t = 0;
            /* include the opening brace */
            token_buf[token_count][t] = line[i];
            t = t + 1;
            i = i + 1;
            while (line[i] && depth > 0) {
                if (line[i] == 123) depth = depth + 1;
                if (line[i] == 125) depth = depth - 1;
                if (t < MAX_TOKEN_LEN - 1) {
                    token_buf[token_count][t] = line[i];
                    t = t + 1;
                }
                i = i + 1;
            }
            if (depth != 0) { /* unterminated brace */
                uart_puts("error: unterminated brace");
                uart_newline();
                return -1;
            }
            token_buf[token_count][t] = 0;
            token_type[token_count] = TOK_BLOCK;
            token_count = token_count + 1;

        } else { /* bare word */
            int t = 0;
            while (line[i] && line[i] != 32 && line[i] != 9
                   && line[i] != 35) { /* stop at space, tab, # */
                if (t < MAX_TOKEN_LEN - 1) {
                    token_buf[token_count][t] = line[i];
                    t = t + 1;
                }
                i = i + 1;
            }
            token_buf[token_count][t] = 0;
            token_type[token_count] = TOK_WORD;
            token_count = token_count + 1;
        }
    }

    return token_count;
}

/* ---- Input buffer ---- */

char line_buf[MAX_LINE_LEN];

int read_line(char *buf, int max) {
    int i = 0;
    int brace_depth = 0;
    while (i < max - 1) {
        int ch = uart_getc();
        if (ch == 4) { /* Ctrl-D: EOF */
            if (i == 0) return -1;
            break;
        }
        if (ch == 10 || ch == 13) { /* newline */
            if (brace_depth <= 0) break;
            /* Inside braces: treat newline as newline in block */
            buf[i] = 10;
            i = i + 1;
            continue;
        }
        buf[i] = ch;
        i = i + 1;
        if (ch == 123) brace_depth = brace_depth + 1; /* '{' */
        if (ch == 125) brace_depth = brace_depth - 1; /* '}' */
    }
    buf[i] = 0;
    return i;
}

