    *(char *)UART_DATA = ch;
}

int uart_getc() {
    while (!(*(char *)UART_STATUS & 0x01)) {}
    return *(char *)UART_DATA;
}

void uart_puts(char *s) {
    while (*s) {
        uart_putc(*s);
        s = s + 1;
    }
}

void uart_putint(int n) {
    if (n < 0) {
        uart_putc(45); /* '-' */
        n = 0 - n;
    }
    if (n == 0) {
        uart_putc(48); /* '0' */
        return;
    }
    char buf[12];
    int i = 0;
    while (n > 0) {
        buf[i] = 48 + n % 10;
        n = n / 10;
        i = i + 1;
    }
    while (i > 0) {
        i = i - 1;
        uart_putc(buf[i]);
    }
}

void uart_newline() {
    uart_putc(10);
}

/* ---- Static allocation limits ---- */

#define MAX_LINE_LEN   512
#define MAX_TOKENS       32
#define MAX_TOKEN_LEN   128
#define MAX_VARS         64
#define MAX_VAR_NAME     32
#define MAX_VAR_VAL     128
#define MAX_NEST         64
#define MAX_FIELDS       16

/* ---- String helpers ---- */

int str_len(char *s) {
    int n = 0;
    while (s[n]) n = n + 1;
    return n;
}

int str_eq(char *a, char *b) {
    int i = 0;
    while (a[i] && b[i]) {
        if (a[i] != b[i]) return 0;
        i = i + 1;
    }
    return a[i] == b[i];
}

void str_copy(char *dst, char *src) {
    int i = 0;
    while (src[i]) {
        dst[i] = src[i];
        i = i + 1;
    }
    dst[i] = 0;
}

int str_starts_with(char *s, char *prefix) {
    int i = 0;
    while (prefix[i]) {
        if (s[i] != prefix[i]) return 0;
        i = i + 1;
    }
    return 1;
}

int str_to_int(char *s) {
    int n = 0;
    int neg = 0;
    int i = 0;
    if (s[0] == 45) { /* '-' */
        neg = 1;
        i = 1;
    }
    while (s[i] >= 48 && s[i] <= 57) { /* '0'-'9' */
        n = n * 10 + (s[i] - 48);
        i = i + 1;
    }
    if (neg) n = 0 - n;
    return n;
}

void int_to_str(char *buf, int n) {
    if (n == 0) {
        buf[0] = 48;
        buf[1] = 0;
        return;
    }
    int neg = 0;
    if (n < 0) {
        neg = 1;
        n = 0 - n;
    }
    char tmp[12];
    int i = 0;
    while (n > 0) {
        tmp[i] = 48 + n % 10;
        n = n / 10;
        i = i + 1;
    }
    int j = 0;
    if (neg) {
        buf[0] = 45;
        j = 1;
    }
    while (i > 0) {
        i = i - 1;
        buf[j] = tmp[i];
        j = j + 1;
    }
    buf[j] = 0;
}

/* ---- Tokenizer ---- */

/* Token types */
#define TOK_WORD   0
#define TOK_QUOTED 1
#define TOK_BLOCK  2

char token_buf[MAX_TOKENS][MAX_TOKEN_LEN];
int  token_type[MAX_TOKENS];
int  token_count;

/* tokenize_line: split a line into tokens.
 * Returns token count, or -1 on syntax error.
 * Fills token_buf[], token_type[], token_count.
 */
int tokenize_line(char *line) {
    int i = 0;
    token_count = 0;

    while (line[i]) {
        /* skip whitespace */
        while (line[i] == 32 || line[i] == 9) /* space, tab */
            i = i + 1;

        if (line[i] == 0) break;

        /* comment — rest of line ignored */
        if (line[i] == 35) /* '#' */
            break;

        if (token_count >= MAX_TOKENS) break;

        if (line[i] == 34) { /* '"' — quoted string */
            i = i + 1; /* skip opening quote */
            int t = 0;
            while (line[i] && line[i] != 34) {
                if (line[i] == 92 && line[i + 1]) { /* backslash escape */
                    i = i + 1;
                    if (line[i] == 110) /* \n */
                        token_buf[token_count][t] = 10;
                    else if (line[i] == 116) /* \t */
                        token_buf[token_count][t] = 9;
                    else
                        token_buf[token_count][t] = line[i];
                    t = t + 1;
                    i = i + 1;
                } else {
                    if (t < MAX_TOKEN_LEN - 1) {
                        token_buf[token_count][t] = line[i];
                        t = t + 1;
                    }
                    i = i + 1;
                }
            }
            if (line[i] != 34) { /* unterminated quote */
                uart_puts("error: unterminated quote");
                uart_newline();
                return -1;
            }
            i = i + 1; /* skip closing quote */
            token_buf[token_count][t] = 0;
            token_type[token_count] = TOK_QUOTED;
            token_count = token_count + 1;

        } else if (line[i] == 123) { /* '{' — brace block */
            int depth = 1;
            int t = 0;
            /* include the opening brace */
            token_buf[token_count][t] = line[i];
            t = t + 1;
            i = i + 1;
            while (line[i] && depth > 0) {
                if (line[i] == 123) depth = depth + 1;
                if (line[i] == 125) depth = depth - 1;
                if (t < MAX_TOKEN_LEN - 1) {
                    token_buf[token_count][t] = line[i];
                    t = t + 1;
                }
                i = i + 1;
            }
            if (depth != 0) { /* unterminated brace */
                uart_puts("error: unterminated brace");
                uart_newline();
                return -1;
            }
            token_buf[token_count][t] = 0;
            token_type[token_count] = TOK_BLOCK;
            token_count = token_count + 1;

        } else { /* bare word */
            int t = 0;
            while (line[i] && line[i] != 32 && line[i] != 9
                   && line[i] != 35) { /* stop at space, tab, # */
                if (t < MAX_TOKEN_LEN - 1) {
                    token_buf[token_count][t] = line[i];
                    t = t + 1;
                }
                i = i + 1;
            }
            token_buf[token_count][t] = 0;
            token_type[token_count] = TOK_WORD;
            token_count = token_count + 1;
        }
    }

    return token_count;
}

/* ---- Input buffer ---- */

char line_buf[MAX_LINE_LEN];

int read_line(char *buf, int max) {
    int i = 0;
    int brace_depth = 0;
    while (i < max - 1) {
        int ch = uart_getc();
        if (ch == 4) { /* Ctrl-D: EOF */
            if (i == 0) return -1;
            break;
        }
        if (ch == 10 || ch == 13) { /* newline */
            if (brace_depth <= 0) break;
            /* Inside braces: treat newline as newline in block */
            buf[i] = 10;
            i = i + 1;
            continue;
        }
        buf[i] = ch;
        i = i + 1;
        if (ch == 123) brace_depth = brace_depth + 1; /* '{' */
        if (ch == 125) brace_depth = brace_depth - 1; /* '}' */
    }
    buf[i] = 0;
    return i;
}

/* ---- Halt ---- */

void halt() {
    asm("_user_halt:");
    asm("bra _user_halt");
}

/* ---- Main ---- */

char *tok_type_name(int t) {
    if (t == TOK_WORD)   return "WORD";
    if (t == TOK_QUOTED) return "QUOTED";
    if (t == TOK_BLOCK)  return "BLOCK";
    return "?";
}

int main() {
    uart_puts("sws 0.1");
    uart_newline();

    while (1) {
        uart_puts("> ");
        int len = read_line(line_buf, MAX_LINE_LEN);
        if (len < 0) break; /* EOF */
        if (len == 0) continue; /* empty line */

        int count = tokenize_line(line_buf);
        if (count < 0) continue; /* syntax error already reported */
        if (count == 0) continue; /* blank or comment-only */

        /* Debug: echo tokens */
        int j = 0;
        while (j < count) {
            uart_puts("[");
            uart_puts(tok_type_name(token_type[j]));
            uart_puts("|");
            uart_puts(token_buf[j]);
            uart_puts("]");
            if (j < count - 1) uart_putc(32); /* space */
            j = j + 1;
        }
        uart_newline();
    }

    halt();
    return 0;
}

